    func authenticate(username: String, password: String, completion: @escaping (Result<Bool, APIError>) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/auth", relativeTo: nil) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let authData = ["username": username, "password": password]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: authData, options: [])
        } catch {
            completion(.failure(.requestFailed))
            return
        }
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.requestFailed))
                return
            }
            
            if httpResponse.statusCode == 200 {
                completion(.success(true))
            } else {
                completion(.failure(.requestFailed))
            }
        }
        
        task.resume()
    }
    
